        """Luồng Optimal Path: Dùng AI giải quyết tác vụ"""
        pass

    @abstractmethod
    def _logic_handler(self, *args, **kwargs) -> Any:
        """Luồng Fallback Path: Dùng Logic cứng khi AI bị sập"""
        pass

    def execute(self, *args, **kwargs) -> Any:
        """
        Mô hình Cầu Dao Điện (Circuit Breaker Pattern - Mốc 17).
        Luôn ưu tiên chạy luồng AI thông minh. Nếu AI thất bại triệt để, tự động bẻ lái sang luồng Logic cơ bản.
